   563→class ToString {
   564→  public static String toString(Object[] a, String s) { return toString(a, s, a.length); }
   565→  public static String toString(Object[] a, String s, int len) {
   566→    StringBuffer result = new StringBuffer();
   567→    for (int i = 0; i < len; i++) {
   568→      if (i > 0) result.append(s);
   569→      Object elt = a[i];
   570→      String eltString = (elt instanceof Object[]) ?
   571→        toString((Object[]) elt, s) : elt.toString();
   572→      result.append(eltString);
   573→    }
   574→    return result.toString();
   575→  }
   576→}
